Herde de `Exception` e adicione contexto:

```python
class SaldoInsuficienteError(Exception):
    def __init__(self, saldo: float, valor: float):
        self.saldo = saldo
        self.valor = valor
        super().__init__(
            f'Saldo {saldo:.2f} insuficiente para saque de {valor:.2f}'
        )

def sacar(saldo: float, valor: float) -> float:
    if valor > saldo:
        raise SaldoInsuficienteError(saldo, valor)
    return saldo - valor

try:
    sacar(100.0, 200.0)
except SaldoInsuficienteError as e:
    print(e)
```

`setUp` roda antes e `tearDown` após cada teste:

```python
import unittest

class TestBancoDeDados(unittest.TestCase):
    def setUp(self):
        """Executado antes de cada test_*"""
        self.conexao = {'host': 'localhost', 'dados': []}

    def tearDown(self):
        """Executado após cada test_*"""
        self.conexao['dados'].clear()

    def test_inserir(self):
        self.conexao['dados'].append('item1')
        self.assertEqual(len(self.conexao['dados']), 1)

    def test_vazio(self):
        self.assertEqual(len(self.conexao['dados']), 0)
```

Anote parâmetros com `: tipo` e retorno com `-> tipo`:

```python
from typing import Optional

def saudacao(nome: str, vezes: int = 1) -> str:
    return (f'Olá, {nome}! ' * vezes).strip()

def buscar_usuario(id: int) -> Optional[dict]:
    usuarios = {1: {'nome': 'Ana'}}
    return usuarios.get(id)  # pode retornar None

print(saudacao('Bob', 2))
print(buscar_usuario(99))  # None
```

Use `patch` para substituir objetos durante o teste:

```python
from unittest import TestCase
from unittest.mock import patch, MagicMock

def buscar_preco(produto_id: int) -> float:
    import requests
    resp = requests.get(f'https://api.exemplo.com/preco/{produto_id}')
    return resp.json()['preco']

class TestBuscarPreco(TestCase):
    @patch('requests.get')
    def test_retorna_preco(self, mock_get):
        mock_get.return_value.json.return_value = {'preco': 99.9}
        resultado = buscar_preco(1)
        self.assertEqual(resultado, 99.9)
        mock_get.assert_called_once()
```

`functools.wraps` preserva os metadados da função original (nome, docstring):

```python
from functools import wraps

def decorator(func):
    @wraps(func)  # sem isso, func.__name__ seria 'wrapper'
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@decorator
def minha_funcao():
    """Minha docstring."""
    pass

print(minha_funcao.__name__)  # 'minha_funcao'
print(minha_funcao.__doc__)   # 'Minha docstring.'
```

Herde de `unittest.TestCase` e prefixe métodos com `test_`:

```python
import unittest

def somar(a, b):
    return a + b

class TestSomar(unittest.TestCase):
    def test_soma_positivos(self):
        self.assertEqual(somar(2, 3), 5)

    def test_soma_negativos(self):
        self.assertEqual(somar(-1, -1), -2)

    def test_soma_zero(self):
        self.assertEqual(somar(0, 5), 5)

if __name__ == '__main__':
    unittest.main()
```

Generators produzem valores sob demanda, economizando memória:

```python
def contador(limite):
    n = 0
    while n < limite:
        yield n
        n += 1

for numero in contador(5):
    print(numero)  # 0 1 2 3 4
```
